urlset:
{# Static pages #}
{% for path, changefreq, priority in static_urls %}

  {{ base }}{{ path }}
  {{ changefreq }}
  {{ priority }}
  {{ now }}

{% endfor %}

{# Experience detail pages #}
{% for exp in experiences %}

  {{ base }}/experience/{{ exp.slug }}
  weekly
  0.8
  {% if exp.updated_at %}
  {{ exp.updated_at.strftime('%Y-%m-%d') }}
  {% else %}
  {{ now }}
  {% endif %}

{% endfor %}

{# Provider public profile pages #}
{% for prov in providers %}

  {{ base }}/providers/{{ prov.business_slug }}
  monthly
  0.6
  {{ now }}

{% endfor %}
